mapper.select:
select achievement_id, user_id, achievement_code, achievement_title, achievement_desc, status, progress_value,
       earned_time, create_by, create_time, update_by, update_time, remark
from sc_user_achievement

  and user_id = #{userId}
  and status = #{status}

order by earned_time desc, achievement_id desc

mapper.update:
update sc_user_achievement
achievement_title = #{achievementTitle}, achievement_desc = #{achievementDesc}, status = #{status}, progress_value = #{progressValue}, earned_time = #{earnedTime}, update_by = #{updateBy}, update_time = sysdate()
where achievement_id = #{achievementId}
